#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 105;
LL T,n,tC,tM,a[N],b[N],c[N],l,r,Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool check(LL mid){
    LL mn=max(0ll,mid-tM+1);
    LL mx=min(mid,tC-1);
    for(int i=1;i<=n;i++){
        LL k=c[i]-a[i]*tC-b[i]*tM+b[i]*mid;
        LL cha=b[i]-a[i];
        //cout<<i<<":\n";
        //cout<<k<<" "<<cha<<"!\n";
        if(cha==0){if(k<0)return 0;}
        else if(cha>0)mx=min(mx,(LL)(floor((LD)(k)/cha)));
        else mn=max(mn,(LL)(ceil((LD)(k)/cha)));
        //cout<<"now ["<<mn<<","<<mx<<"]\n";
    }return (mn<=mx);
}
int main(){
    T=read();
    while(T--){
        n=read(),tC=read(),tM=read();
        for(int i=1;i<=n;i++)
            a[i]=read(),b[i]=read(),c[i]=read();
        l=0,r=tC+tM-2,Ans=r;
        while(l<=r){
            LL mid=(l+r)>>1;
            if(check(mid))Ans=mid,r=mid-1;
            else l=mid+1;
        }cout<<Ans<<"\n";
    }
    return 0;
}
